const { Storage } = require('@google-cloud/storage');
const express = require('express');

// Initialize Cloud Storage client
const storage = new Storage();

// Create an Express app
const app = express();
app.use(express.json());

// Set up CORS headers to allow requests from any origin
app.use((req, res, next) => {
  res.header("Access-Control-Allow-Origin", "*");
  res.header("Access-Control-Allow-Headers", "Origin, X-Requested-With, Content-Type, Accept");
  next();
});

// Serve files from Cloud Storage based on HTTP request path parameter
app.get('/serve/:bucket/:filePath', async (req, res) => {
  const bucketName = req.params.bucket;
  const filePath = req.params.filePath;

  try {
    // Get the file from Cloud Storage and stream it to the response
    const file = storage.bucket(bucketName).file(filePath);
    const [stream] = await file.createReadStream().createWriteStream();
    res.set("Content-Disposition", `attachment; filename="${filePath}"`);
    stream.pipe(res);
  } catch (error) {
    console.error(error);
    res.status(404).send(`File not found: ${filePath}`);
  }
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});